files.shader.frag:
precision mediump float;
uniform vec2 u_resolution;
uniform float u_time;

float sdCircle(vec2 p, float r) {
  return length(p) - r;
}

float sdBox(vec2 p, vec2 b) {
  vec2 d = abs(p) - b;
  return length(max(d, 0.0)) + min(max(d.x, d.y), 0.0);
}

float smin(float a, float b, float k) {
  float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
  return mix(b, a, h) - k * h * (1.0 - h);
}

void main() {
  vec2 p = (gl_FragCoord.xy - u_resolution * 0.5) / u_resolution.y;
  float t = u_time * 0.8;
  float d1 = sdCircle(p - vec2(sin(t) * 0.25, 0.0), 0.25);
  float d2 = sdBox(p - vec2(0.2, 0.0), vec2(0.2, 0.2));
  float d = smin(d1, d2, 0.15);
  float shape = 1.0 - smoothstep(-0.005, 0.005, d);
  gl_FragColor = vec4(vec3(shape), 1.0);
}
